File: backend/server.js
Lines 1-139:
  1 | /**
  2 |  * S:\workspace Infer Server
  3 |  * 
  4 |  * HTTP server that exposes the /infer endpoint for Oracle to call
  5 |  * This is the "Muscle" part of the Oracle (Brain) + Cockpit (Muscle) architecture
  6 |  * 
  7 |  * Run: node server.js
  8 |  * 
  9 |  * Endpoints:
 10 |  * - POST /api/infer - Model inference
 11 |  * - GET  /api/infer/health - Health check
 12 |  * - GET  /api/infer/models - List available models
 13 |  */
 14 | 
 15 | const http = require('http');
 16 | const { handleInfer, handleHealth, handleModels } = require('./routes/api/infer');
 17 | 
 18 | const PORT = process.env.PORT || 3847; // Different port to avoid conflicts
 19 | const HOST = process.env.HOST || '0.0.0.0';
 20 | 
 21 | /**
 22 |  * Parse JSON body from request
 23 |  */
 24 | function parseBody(req) {
 25 |   return new Promise((resolve, reject) => {
 26 |     let body = '';
 27 |     req.on('data', chunk => body += chunk);
 28 |     req.on('end', () => {
 29 |       try {
 30 |         resolve(body ? JSON.parse(body) : {});
 31 |       } catch (e) {
 32 |         reject(e);
 33 |       }
 34 |     });
 35 |     req.on('error', reject);
 36 |   });
 37 | }
 38 | 
 39 | /**
 40 |  * Create HTTP response
 41 |  */
 42 | function sendResponse(res, statusCode, data) {
 43 |   res.writeHead(statusCode, {
 44 |     'Content-Type': 'application/json',
 45 |     'Access-Control-Allow-Origin': '*',
 46 |     'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
 47 |     'Access-Control-Allow-Headers': 'Content-Type'
 48 |   });
 49 |   res.end(JSON.stringify(data));
 50 | }
 51 | 
 52 | /**
 53 |  * Handle CORS preflight
 54 |  */
 55 | function handleCors(res) {
 56 |   res.writeHead(204, {
 57 |     'Access-Control-Allow-Origin': '*',
 58 |     'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
 59 |     'Access-Control-Allow-Headers': 'Content-Type'
 60 |   });
 61 |   res.end();
 62 | }
 63 | 
 64 | /**
 65 |  * Main request handler
 66 |  */
 67 | async function handleRequest(req, res) {
 68 |   const url = req.url.split('?')[0];
 69 |   const method = req.method;
 70 | 
 71 |   console.log(`[server] ${method} ${url}`);
 72 | 
 73 |   // Handle CORS preflight
 74 |   if (method === 'OPTIONS') {
 75 |     return handleCors(res);
 76 |   }
 77 | 
 78 |   try {
 79 |     // Route: POST /api/infer
 80 |     if (method === 'POST' && url === '/api/infer') {
 81 |       const body = await parseBody(req);
 82 |       return handleInfer({ body }, res);
 83 |     }
 84 | 
 85 |     // Route: GET /api/infer/health
 86 |     if (method === 'GET' && url === '/api/infer/health') {
 87 |       return handleHealth({ query: {} }, res);
 88 |     }
 89 | 
 90 |     // Route: GET /api/infer/models
 91 |     if (method === 'GET' && url === '/api/infer/models') {
 92 |       return handleModels({ query: {} }, res);
 93 |     }
 94 | 
 95 |     // 404 for unknown routes
 96 |     sendResponse(res, 404, {
 97 |       success: false,
 98 |       error: 'Not Found',
 99 |       message: `No route for ${method} ${url}`
100 |     });
101 | 
102 |   } catch (error) {
103 |     console.error(`[server] Error: ${error.message}`);
104 |     sendResponse(res, 500, {
105 |       success: false,
106 |       error: 'Internal Server Error',
107 |       message: error.message
108 |     });
109 |   }
110 | }
111 | 
112 | // Create and start server
113 | const server = http.createServer(handleRequest);
114 | 
115 | server.listen(PORT, HOST, () => {
116 |   console.log(`
117 | ╔═══════════════════════════════════════════════════════════╗
118 | ║   S:\\workspace Infer Server - Running                     ║
119 | ║                                                           ║
120 | ║   Host: http://${HOST}:${PORT}                        ║
121 | ║                                                           ║
122 | ║   Endpoints:                                             ║
123 | ║   - POST /api/infer         Model inference              ║
124 | ║   - GET  /api/infer/health  Health check                 ║
125 | ║   - GET  /api/infer/models  List available models       ║
126 | ║                                                           ║
127 | ║   Oracle can connect to this endpoint for local inference║
128 | ╚═══════════════════════════════════════════════════════════╝
129 |   `);
130 | });
131 | 
132 | // Handle graceful shutdown
133 | process.on('SIGINT', () => {
134 |   console.log('\n[server] Shutting down...');
135 |   server.close(() => {
136 |     console.log('[server] Server stopped');
137 |     process.exit(0);
138 |   });
139 | });


