  1 | /**
  2 |  * S:\workspace Infer Endpoint
  3 |  * 
  4 |  * Exposes local model inference capability to Oracle (C:\_bootstrap)
  5 |  * Supports multiple backends: Ollama, LM Studio, or custom
  6 |  * 
  7 |  * Endpoint: POST /api/infer
  8 |  * 
  9 |  * Request Body:
 10 |  * {
 11 |  *   prompt: string,        // The prompt to send to the model
 12 |  *   model?: string,        // Optional model name (defaults to configured default)
 13 |  *   temperature?: number,  // Optional temperature setting
 14 |  *   maxTokens?: number,   // Optional max tokens
 15 |  *   provider?: string     // Optional: 'ollama', 'lm-studio' (default: from env)
 16 |  * }
 17 |  * 
 18 |  * Response:
 19 |  * {
 20 |  *   success: boolean,
 21 |  *   response: string,      // Model's text response
 22 |  *   model: string,         // Model used
 23 |  *   tokens?: number        // Number of tokens in response
 24 |  * }
 25 |  */
 26 | 
 27 | // Configuration
 28 | const INFER_PROVIDER = process.env.INFER_PROVIDER || 'ollama'; // 'ollama' or 'lm-studio'
 29 | const OLLAMA_HOST = process.env.OLLAMA_HOST || 'http://localhost:11434';
 30 | const LM_STUDIO_URL = process.env.LM_STUDIO_URL || 'http://localhost:1234';
 31 | const LM_STUDIO_API_TOKEN = process.env.LM_STUDIO_API_TOKEN || '';
 32 | const DEFAULT_MODEL = process.env.DEFAULT_MODEL || 'llama3.2:8b';
 33 | 
 34 | /**
 35 |  * Call LM Studio v1 API
 36 |  */
 37 | async function callLMStudio(prompt, model, temperature, maxTokens) {
 38 |   const response = await fetch(`${LM_STUDIO_URL}/api/v1/chat`, {
 39 |     method: 'POST',
 40 |     headers: {
 41 |       'Content-Type': 'application/json',
 42 |       ...(LM_STUDIO_API_TOKEN ? { 'Authorization': `Bearer ${LM_STUDIO_API_TOKEN}` } : {})
 43 |     },
 44 |     body: JSON.stringify({
 45 |       model,
 46 |       messages: [{ role: 'user', content: prompt }],
 47 |       temperature,
 48 |       max_tokens: maxTokens,
 49 |       stream: false
 50 |     })
 51 |   });
 52 | 
 53 |   if (!response.ok) {
 54 |     const errorText = await response.text();
 55 |     throw new Error(`LM Studio error: ${response.status} - ${errorText}`);
 56 |   }
 57 | 
 58 |   const result = await response.json();
 59 |   return {
 60 |     response: result.message?.content || '',
 61 |     model: result.model,
 62 |     tokens: (result.prompt_eval_count || 0) + (result.eval_count || 0),
 63 |     done: result.done
 64 |   };
 65 | }
 66 | 
 67 | /**
 68 |  * Call Ollama API
 69 |  */
 70 | async function callOllama(prompt, model, temperature, maxTokens) {
 71 |   const response = await fetch(`${OLLAMA_HOST}/api/generate`, {
 72 |     method: 'POST',
 73 |     headers: {
 74 |       'Content-Type': 'application/json'
 75 |     },
 76 |     body: JSON.stringify({
 77 |       model,
 78 |       prompt,
 79 |       temperature,
 80 |       max_tokens: maxTokens,
 81 |       stream: false
 82 |     })
 83 |   });
 84 | 
 85 |   if (!response.ok) {
 86 |     const errorText = await response.text();
 87 |     throw new Error(`Ollama error: ${response.status} - ${errorText}`);
 88 |   }
 89 | 
 90 |   const result = await response.json();
 91 |   return {
 92 |     response: result.response || '',
 93 |     model,
 94 |     tokens: result.eval_count || result.prompt_eval_count,
 95 |     done: result.done,
 96 |     context: result.context
 97 |   };
 98 | }
 99 | 
100 | /**
101 |  * Handle inference requests
102 |  * @param {Object} req - Express request object
103 |  * @param {Object} res - Express response object
104 |  */
105 | async function handleInfer(req, res) {
106 |   try {
107 |     const { 
108 |       prompt, 
109 |       model = DEFAULT_MODEL, 
110 |       temperature = 0.7, 
111 |       maxTokens = 2048,
112 |       provider = INFER_PROVIDER
113 |     } = req.body;
114 | 
115 |     // Validate prompt
116 |     if (!prompt || typeof prompt !== 'string') {
117 |       return res.status(400).json({
118 |         success: false,
119 |         error: 'Missing or invalid "prompt" field'
120 |       });
121 |     }
122 | 
123 |     // Validate model is allowed (security check)
124 |     const allowedModels = [
125 |       'llama3.2:8b', 'llama3.1:8b', 'llama3.2', 'llama3.1',
126 |       'phi3:3.8b', 'phi3', 'mistral:7b', 'mistral',
127 |       'deepseek-coder:6.7b', 'deepseek-coder', 'codellama:7b', 'codellama',
128 |       'meditron:7b', 'qwen2.5:14b', 'qwen2.5', 'qwen2'
129 |     ];
130 |     
131 |     const baseModel = model.split(':')[0];
132 |     if (!allowedModels.includes(model) && !allowedModels.some(m => m.startsWith(baseModel))) {
133 |       console.warn(`[infer] Using model: ${model} (not in explicit allowlist)`);
134 |     }
135 | 
136 |     console.log(`[infer] Request - provider: ${provider}, model: ${model}, prompt length: ${prompt.length}`);
137 | 
138 |     // Route to appropriate provider
139 |     let result;
140 |     if (provider === 'lm-studio') {
141 |       result = await callLMStudio(prompt, model, temperature, maxTokens);
142 |     } else {
143 |       // Default to Ollama
144 |       result = await callOllama(prompt, model, temperature, maxTokens);
145 |     }
146 |     
147 |     console.log(`[infer] Success - response length: ${result.response?.length || 0}`);
148 | 
149 |     // Return the response
150 |     res.json({
151 |       success: true,
152 |       response: result.response || '',
153 |       model: result.model,
154 |       tokens: result.tokens,
155 |       done: result.done,
156 |       provider: provider
157 |     });
158 | 
159 |   } catch (error) {
160 |     console.error(`[infer] Error: ${error.message}`);
161 |     res.status(500).json({
162 |       success: false,
163 |       error: 'Inference failed',
164 |       message: error.message
165 |     });
166 |   }
167 | }
168 | 
169 | /**
170 |  * Handle chat requests (messages format for LM Studio)
171 |  * @param {Object} req - Express request object
172 |  * @param {Object} res - Express response object
173 |  */
174 | async function handleChat(req, res) {
175 |   try {
176 |     const { 
177 |       messages,
178 |       model = DEFAULT_MODEL, 
179 |       temperature = 0.7, 
180 |       maxTokens = 2048,
181 |       provider = INFER_PROVIDER,
182 |       contextLength
183 |     } = req.body;
184 | 
185 |     if (!messages || !Array.isArray(messages)) {
186 |       return res.status(400).json({
187 |         success: false,
188 |         error: 'Missing or invalid "messages" array'
189 |       });
190 |     }
191 | 
192 |     console.log(`[chat] Request - provider: ${provider}, model: ${model}, messages: ${messages.length}`);
193 | 
194 |     if (provider === 'lm-studio') {
195 |       // Use LM Studio native chat
196 |       const requestBody = {
197 |         model,
198 |         messages,
199 |         temperature,
200 |         max_tokens: maxTokens,
201 |         stream: false
202 |       };
203 |       if (contextLength) requestBody.context_length = contextLength;
204 | 
205 |       const response = await fetch(`${LM_STUDIO_URL}/api/v1/chat`, {
206 |         method: 'POST',
207 |         headers: {
208 |           'Content-Type': 'application/json',
209 |           ...(LM_STUDIO_API_TOKEN ? { 'Authorization': `Bearer ${LM_STUDIO_API_TOKEN}` } : {})
210 |         },
211 |         body: JSON.stringify(requestBody)
212 |       });
213 | 
214 |       if (!response.ok) {
215 |         const errorText = await response.text();
216 |         throw new Error(`LM Studio chat failed: ${response.status} - ${errorText}`);
217 |       }
218 | 
219 |       const result = await response.json();
220 |       return res.json({
221 |         success: true,
222 |         message: result.message,
223 |         model: result.model,
224 |         done: result.done,
225 |         metrics: {
226 |           promptTokens: result.prompt_eval_count,
227 |           completionTokens: result.eval_count,
228 |           totalTokens: (result.prompt_eval_count || 0) + (result.eval_count || 0)
229 |         },
230 |         provider: 'lm-studio'
231 |       });
232 |     } else {
233 |       // Convert messages to prompt for Ollama
234 |       const prompt = messages.map(m => `${m.role}: ${m.content}`).join('\n');
235 |       const result = await callOllama(prompt, model, temperature, maxTokens);
236 |       
237 |       return res.json({
238 |         success: true,
239 |         message: { role: 'assistant', content: result.response },
240 |         model: result.model,
241 |         done: result.done,
242 |         tokens: result.tokens,
243 |         provider: 'ollama'
244 |       });
245 |     }
246 | 
247 |   } catch (error) {
248 |     console.error(`[chat] Error: ${error.message}`);
249 |     res.status(500).json({
250 |       success: false,
251 |       error: 'Chat failed',
252 |       message: error.message
253 |     });
254 |   }
255 | }
256 | 
257 | /**
258 |  * Health check for the infer endpoint
259 |  * @param {Object} req - Express request object
260 |  * @param {Object} res - Express response object
261 |  */
262 | async function handleHealth(req, res) {
263 |   const health = {
264 |     service: 'infer',
265 |     provider: INFER_PROVIDER,
266 |     defaultModel: DEFAULT_MODEL,
267 |     timestamp: new Date().toISOString()
268 |   };
269 | 
270 |   // Check Ollama
271 |   try {
272 |     const ollamaResponse = await fetch(`${OLLAMA_HOST}/api/tags`, {
273 |       method: 'GET',
274 |       signal: AbortSignal.timeout(5000)
275 |     });
276 | 
277 |     if (ollamaResponse.ok) {
278 |       const data = await ollamaResponse.json();
279 |       health.ollama = {
280 |         status: 'available',
281 |         host: OLLAMA_HOST,
282 |         models: data.models?.map(m => m.name) || []
283 |       };
284 |     } else {
285 |       health.ollama = { status: 'error', host: OLLAMA_HOST };
286 |     }
287 |   } catch (error) {
288 |     health.ollama = { status: 'unavailable', host: OLLAMA_HOST, error: error.message };
289 |   }
290 | 
291 |   // Check LM Studio
292 |   try {
293 |     const lmResponse = await fetch(`${LM_STUDIO_URL}/api/v1/models`, {
294 |       method: 'GET',
295 |       headers: LM_STUDIO_API_TOKEN ? { 'Authorization': `Bearer ${LM_STUDIO_API_TOKEN}` } : {},
296 |       signal: AbortSignal.timeout(5000)
297 |     });
298 | 
299 |     if (lmResponse.ok) {
300 |       const data = await lmResponse.json();
301 |       health.lmStudio = {
302 |         status: 'available',
303 |         url: LM_STUDIO_URL,
304 |         models: data.data?.map(m => m.id) || []
305 |       };
306 |     } else {
307 |       health.lmStudio = { status: 'error', url: LM_STUDIO_URL };
308 |     }
309 |   } catch (error) {
310 |     health.lmStudio = { status: 'unavailable', url: LM_STUDIO_URL, error: error.message };
311 |   }
312 | 
313 |   // Overall status
314 |   if (INFER_PROVIDER === 'lm-studio' && health.lmStudio?.status === 'available') {
315 |     health.status = 'healthy';
316 |   } else if (INFER_PROVIDER === 'ollama' && health.ollama?.status === 'available') {
317 |     health.status = 'healthy';
318 |   } else {
319 |     health.status = 'degraded';
320 |   }
321 | 
322 |   res.writeHead(200, { "Content-Type": "application/json" });
323 | res.end(JSON.stringify(health));
324 | }
325 | 
326 | /**
327 |  * List available models
328 |  * @param {Object} req - Express request object
329 |  * @param {Object} res - Express response object
330 |  */
331 | async function handleModels(req, res) {
332 |   const provider = req.query.provider || INFER_PROVIDER;
333 |   
334 |   try {
335 |     if (provider === 'lm-studio') {
336 |       const response = await fetch(`${LM_STUDIO_URL}/api/v1/models`, {
337 |         method: 'GET',
338 |         headers: LM_STUDIO_API_TOKEN ? { 'Authorization': `Bearer ${LM_STUDIO_API_TOKEN}` } : {},
339 |         signal: AbortSignal.timeout(10000)
340 |       });
341 |       
342 |       if (!response.ok) throw new Error(`LM Studio returned ${response.status}`);
343 |       const data = await response.json();
344 |       
345 |       return res.json({
346 |         success: true,
347 |         provider: 'lm-studio',
348 |         models: data.data || []
349 |       });
350 |     } else {
351 |       const response = await fetch(`${OLLAMA_HOST}/api/tags`, {
352 |         method: 'GET',
353 |         signal: AbortSignal.timeout(10000)
354 |       });
355 |       
356 |       if (!response.ok) throw new Error(`Ollama returned ${response.status}`);
357 |       const data = await response.json();
358 |       
359 |       return res.json({
360 |         success: true,
361 |         provider: 'ollama',
362 |         models: data.models || []
363 |       });
364 |     }
365 |   } catch (error) {
366 |     console.error(`[infer] Models error: ${error.message}`);
367 |     res.status(500).json({
368 |       success: false,
369 |       error: 'Failed to fetch models',
370 |       message: error.message
371 |     });
372 |   }
373 | }
374 | 
375 | /**
376 |  * Load model (LM Studio only)
377 |  */
378 | async function handleLoadModel(req, res) {
379 |   const { model } = req.body;
380 |   
381 |   if (!model) {
382 |     return res.status(400).json({ success: false, error: 'model is required' });
383 |   }
384 | 
385 |   try {
386 |     const response = await fetch(`${LM_STUDIO_URL}/api/v1/models/load`, {
387 |       method: 'POST',
388 |       headers: {
389 |         'Content-Type': 'application/json',
390 |         ...(LM_STUDIO_API_TOKEN ? { 'Authorization': `Bearer ${LM_STUDIO_API_TOKEN}` } : {})
391 |       },
392 |       body: JSON.stringify({ model })
393 |     });
394 | 
395 |     if (!response.ok) {
396 |       const errorText = await response.text();
397 |       throw new Error(`Load failed: ${response.status} - ${errorText}`);
398 |     }
399 | 
400 |     const result = await response.json();
401 |     res.json({ success: true, model, details: result });
402 | 
403 |   } catch (error) {
404 |     console.error(`[infer] Load model error: ${error.message}`);
405 |     res.status(500).json({ success: false, error: error.message });
406 |   }
407 | }
408 | 
409 | /**
410 |  * Unload model (LM Studio only)
411 |  */
412 | async function handleUnloadModel(req, res) {
413 |   const { model } = req.body;
414 |   
415 |   if (!model) {
416 |     return res.status(400).json({ success: false, error: 'model is required' });
417 |   }
418 | 
419 |   try {
420 |     const response = await fetch(`${LM_STUDIO_URL}/api/v1/models/unload`, {
421 |       method: 'POST',
422 |       headers: {
423 |         'Content-Type': 'application/json',
424 |         ...(LM_STUDIO_API_TOKEN ? { 'Authorization': `Bearer ${LM_STUDIO_API_TOKEN}` } : {})
425 |       },
426 |       body: JSON.stringify({ model })
427 |     });
428 | 
429 |     if (!response.ok) {
430 |       const errorText = await response.text();
431 |       throw new Error(`Unload failed: ${response.status} - ${errorText}`);
432 |     }
433 | 
434 |     res.json({ success: true, model });
435 | 
436 |   } catch (error) {
437 |     console.error(`[infer] Unload model error: ${error.message}`);
438 |     res.status(500).json({ success: false, error: error.message });
439 |   }
440 | }
441 | 
442 | // Export handlers for Express
443 | module.exports = {
444 |   handleInfer,
445 |   handleChat,
446 |   handleHealth,
447 |   handleModels,
448 |   handleLoadModel,
449 |   handleUnloadModel
450 | };


