411 | function handleExecuteCommand(ws, data) {
412 |   const { command, shell = 'bash', cwd } = data;
413 |   
414 |   if (!command) {
415 |     ws.send(JSON.stringify({ 
416 |       type: 'command_result', 
417 |       success: false, 
418 |       error: 'No command provided' 
419 |     }));
420 |     return;
421 |   }
422 |   
423 |   console.log(`[Server] Executing: ${command}`);
424 |   
425 |   const isWindows = process.platform === 'win32';
426 |   let shellCmd, args;
427 |   
428 |   if (shell === 'powershell' || (shell === 'bash' && isWindows)) {
429 |     shellCmd = isWindows ? 'powershell' : '/bin/bash';
430 |     args = isWindows ? ['-Command', command] : ['-c', command];
431 |   } else {
432 |     shellCmd = isWindows ? 'cmd' : '/bin/sh';
433 |     args = isWindows ? ['/c', command] : ['-c', command];
434 |   }
435 |   
436 |   const child = spawn(shellCmd, args, {
437 |     cwd: cwd || process.cwd(),
438 |     timeout: 60000,
439 |     maxBuffer: 10 * 1024 * 1024
440 |   });
441 |   
442 |   let stdout = '';
443 |   let stderr = '';
444 |   
445 |   child.stdout.on('data', (chunk) => {
446 |     stdout += chunk.toString();
447 |     ws.send(JSON.stringify({
448 |       type: 'command_output',
449 |       stream: 'stdout',
450 |       data: chunk.toString()
451 |     }));
452 |   });
453 |   
454 |   child.stderr.on('data', (chunk) => {
455 |     stderr += chunk.toString();
456 |     ws.send(JSON.stringify({
457 |       type: 'command_output',
458 |       stream: 'stderr',
459 |       data: chunk.toString()
460 |     }));
461 |   });
462 |   
463 |   child.on('close', (code) => {
464 |     ws.send(JSON.stringify({
465 |       type: 'command_result',
466 |       success: code === 0,
467 |       exitCode: code,
468 |       stdout: stdout.slice(-100000),
469 |       stderr: stderr.slice(-50000)
470 |     }));
471 |   });
472 |   
473 |   child.on('error', (err) => {
474 |     ws.send(JSON.stringify({
475 |       type: 'command_result',
476 |       success: false,
477 |       error: err.message
478 |     }));
479 |   });
480 | }
